import{_ as e,o as a,c as r,ak as d,aI as i,aJ as l,aK as o,aL as n,aM as S,aN as p,aO as A,aP as s,aQ as h,aR as c}from"./chunks/framework.DXL0ymeD.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"AUTOSAR Theory/AUTOSAR 概论.md","filePath":"AUTOSAR Theory/AUTOSAR 概论.md"}'),_={name:"AUTOSAR Theory/AUTOSAR 概论.md"};function T(m,t,R,f,b,O){return a(),r("div",null,[...t[0]||(t[0]=[d('<p>AUTOSAR - AUTOMOTIVE OPEN SYSTEM ARCHITECTURE</p><h2 id="分类" tabindex="-1">分类 <a class="header-anchor" href="#分类" aria-label="Permalink to “分类”">​</a></h2><p>AUTOSAR 分为 AUTPSAR CP (Classic Platform) 和 AUTOSAR AP (Adaptive Platform)。目前流行的是 AUTOSAR CP。</p><p>Classic Platform 是 AUTOSAR 针对具有<strong>硬实时性</strong>和<strong>安全性</strong>约束的嵌入式系统提供的解决方案，它包含大量应用程序接口，涵盖以下五个车辆领域：车身和舒适性、动力总成发动机、动力总成变速器、底盘控制以及乘员和行人安全。</p><p>Adaptive Platform 是 AUTOSAR 为高性能计算 ECU 提供的解决方案，用于构建故障运行系统，以应用于自动驾驶等场景。</p><h2 id="autosar-cp-架构" tabindex="-1">AUTOSAR CP 架构 <a class="header-anchor" href="#autosar-cp-架构" aria-label="Permalink to “AUTOSAR CP 架构”">​</a></h2><p>AUTOSAR Classic 平台架构在最高抽象级别上区分了在微控制器上运行的三个软件层：应用程序 (Application, ASW)、运行时环境 (Runtime Environment, RTE) 和基础软件 (Basic Sowtware, BSW)。</p><ul><li>应用软件层基本与硬件无关。</li><li>软件组件之间的通信以及通过 RTE 访问 BSW。</li><li>RTE 代表应用程序的完整接口。</li><li>BSW 分为三个主要层和复杂的驱动因素： <ul><li>服务、ECU（电子控制单元）抽象和微控制器抽象 (MCAL)。</li><li>服务进一步细分为功能组，分别代表系统、内存和通信服务的基础设施。</li></ul></li></ul><p><img src="'+i+'" alt=""></p><h2 id="autosar-标准文件-结构-部分" tabindex="-1">AUTOSAR 标准文件 结构（部分） <a class="header-anchor" href="#autosar-标准文件-结构-部分" aria-label="Permalink to “AUTOSAR 标准文件 结构（部分）”">​</a></h2><h3 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to “General”">​</a></h3><table tabindex="0"><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>AUTOSAR_EXP_LayeredSoftwareArchitecture.pdf</td><td>描述 AUTOSAR 分层软件架构</td></tr><tr><td>AUTOSAR_RS_Features.pdf</td><td>描述 AUTOSAR 所有功能</td></tr><tr><td>AUTOSAR_SWS_BulkNvDataManager.pdf</td><td>定义基础软件模块 BulkNvDataManager 规范</td></tr><tr><td>AUTOSAR_EXP_VFB.pdf</td><td>定义 AUTOSAR 虚拟功能总线（VFB）</td></tr></tbody></table><h3 id="methodology-and-templates" tabindex="-1">Methodology and Templates <a class="header-anchor" href="#methodology-and-templates" aria-label="Permalink to “Methodology and Templates”">​</a></h3><table tabindex="0"><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>AUTOSAR_TPS_BSWModuleDescriptionTemplate.pdf</td><td>定义 BSWMDT（基础软件模块描述模板）</td></tr><tr><td>AUTOSAR_CP_TPS_SoftwareComponentTemplate</td><td>定义 SWCDT</td></tr><tr><td>AUTOSAR_TPS_DiagnosticExtractTemplate.pdf</td><td>定义 DiagnosticExtract（诊断摘要）规范</td></tr><tr><td>AUTOSAR_TR_FrancaIntegration.pdf</td><td>聚焦 AUTOSAR 与 GENIVI 体系的集成</td></tr><tr><td>AUTOSAR_TR_Methodology.pdf</td><td>定义 AUTOSAR 开发方法</td></tr><tr><td>AUTOSAR_EXP_ModelingShowCases.zip</td><td>建模展示案例的补充材料</td></tr><tr><td>AUTOSAR_TR_ModelingShowCases.pdf</td><td>配套上述 zip 包的说明文档</td></tr><tr><td>AUTOSAR_RS_BSWModuleDescriptionTemplate.pdf</td><td>收集 BSWMDT 的需求</td></tr><tr><td>AUTOSAR_RS_DiagnosticExtractTemplate.pdf</td><td>收集 DiagnosticExtract 的需求</td></tr></tbody></table><h3 id="io" tabindex="-1">IO <a class="header-anchor" href="#io" aria-label="Permalink to “IO”">​</a></h3><table tabindex="0"><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>AUTOSAR_SRS_ADCDriver.pdf</td><td>规定 ADC 驱动需求</td></tr><tr><td>AUTOSAR_SRS_DIODriver.pdf</td><td>规定 DIO 驱动需求</td></tr><tr><td>AUTOSAR_SWS_PWMDriver.pdf</td><td>定义 PWM 驱动的 API 与配置</td></tr><tr><td>AUTOSAR_SWS_IOHardwareAbstraction.pdf</td><td>实现 IO 硬件抽象</td></tr><tr><td>...</td><td>...</td></tr></tbody></table><h3 id="libraries" tabindex="-1">Libraries <a class="header-anchor" href="#libraries" aria-label="Permalink to “Libraries”">​</a></h3><table tabindex="0"><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>AUTOSAR_SWS_BSWMulticoreLibrary.pdf</td><td>提供原子操作例程</td></tr><tr><td>AUTOSAR_SWS_CRCLibrary.pdf</td><td>支持多类型 CRC 计算</td></tr><tr><td>AUTOSAR_SWS_E2ELibrary.pdf</td><td>安全数据传输保护</td></tr><tr><td>AUTOSAR_SWS_MFXLibrary.pdf</td><td>定点算术运算</td></tr></tbody></table><h3 id="diagnostics" tabindex="-1">Diagnostics <a class="header-anchor" href="#diagnostics" aria-label="Permalink to “Diagnostics”">​</a></h3><table tabindex="0"><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>AUTOSAR_SWS_DiagnosticCommunicationManager.pdf</td><td>诊断服务通用 API</td></tr><tr><td>AUTOSAR_SWS_SAEJ1939DiagnosticCommunicationManager.pdf</td><td>适配 SAE J1939-73 标准</td></tr><tr><td>AUTOSAR_SWS_DiagnosticEventManager.pdf</td><td>故障处理与存储</td></tr></tbody></table><h3 id="safety" tabindex="-1">Safety <a class="header-anchor" href="#safety" aria-label="Permalink to “Safety”">​</a></h3><table tabindex="0"><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>AUTOSAR_SWS_WatchdogDriver.pdf</td><td>看门狗驱动</td></tr><tr><td>AUTOSAR_SWS_WatchdogManager.pdf</td><td>看门狗管理</td></tr><tr><td>AUTOSAR_TPS_SafetyExtensions.pdf</td><td>安全信息标准化交换</td></tr><tr><td>AUTOSAR_EXP_FunctionalSafetyMeasures.pdf</td><td>功能安全机制</td></tr></tbody></table><h3 id="bsw-general" tabindex="-1">BSW General <a class="header-anchor" href="#bsw-general" aria-label="Permalink to “BSW General”">​</a></h3><table tabindex="0"><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>AUTOSAR_SRS_BSWGeneral.pdf</td><td>BSW 通用需求</td></tr><tr><td>AUTOSAR_SWS_CompilerAbstraction.pdf</td><td>封装编译器特定关键字</td></tr><tr><td>AUTOSAR_SWS_PlatformTypes.pdf</td><td>定义平台相关类型</td></tr><tr><td>AUTOSAR_EXP_ErrorDescription.pdf</td><td>描述 BSW 错误类型</td></tr><tr><td>AUTOSAR_EXP_InterruptHandlingExplanation.pdf</td><td>中断配置与处理</td></tr><tr><td>AUTOSAR_EXP_CDDDesignAndIntegrationGuideline.pdf</td><td>复杂驱动（CDD）设计</td></tr></tbody></table><h3 id="release-documentation" tabindex="-1">Release Documentation <a class="header-anchor" href="#release-documentation" aria-label="Permalink to “Release Documentation”">​</a></h3><table tabindex="0"><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>AUTOSAR_TR_ClassicPlatformReleaseOverview.pdf</td><td>CP 文档的总览说明与逻辑</td></tr></tbody></table><h3 id="communication" tabindex="-1">Communication <a class="header-anchor" href="#communication" aria-label="Permalink to “Communication”">​</a></h3><table tabindex="0"><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>AUTOSAR_SWS_CANDriver.pdf</td><td>CAN 驱动规范</td></tr><tr><td>AUTOSAR_SWS_SAEJ1939TransportLayer.pdf</td><td>适配 SAE J1939 标准的传输层模块（J1939Tp）</td></tr><tr><td>AUTOSAR_SWS_BusMirroring.pdf</td><td>内部总线流量复制到外部总线</td></tr><tr><td>AUTOSAR_SRS_NetworkManagement.pdf</td><td>定义网络管理需求</td></tr><tr><td>AUTOSAR_SRS_SecureOnboardCommunication.pdf</td><td>SecOC 安全车载通信</td></tr><tr><td>AUTOSAR_ASWS_TransformerGeneral.pdf</td><td>Transformer 数据转换</td></tr></tbody></table><h3 id="memory" tabindex="-1">Memory <a class="header-anchor" href="#memory" aria-label="Permalink to “Memory”">​</a></h3><table tabindex="0"><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>AUTOSAR_SWS_NVRAMManager.pdf</td><td>NvM 模块：管理非易失性数据</td></tr><tr><td>AUTOSAR_SWS_FlashDriver.pdf</td><td>内部 / 外部 Flash 驱动</td></tr><tr><td>AUTOSAR_SWS_EEPROMAbstraction.pdf</td><td>EEPROM 抽象</td></tr><tr><td>AUTOSAR_SWS_FlashEEPROMEmulation.pdf</td><td>FEE 闪存仿真 EEPROM</td></tr><tr><td>AUTOSAR_EXP_FirmwareOverTheAir.pdf</td><td>空中固件升级机制</td></tr><tr><td>AUTOSAR_SWS_RAMTest.pdf</td><td>RAM 内存测试模块</td></tr></tbody></table><h3 id="system-services" tabindex="-1">System Services <a class="header-anchor" href="#system-services" aria-label="Permalink to “System Services”">​</a></h3><table tabindex="0"><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>AUTOSAR_SWS_OS.pdf</td><td>AUTOSAR OS 规范</td></tr><tr><td>AUTOSAR_SWS_COMManager.pdf</td><td>ComM 模块</td></tr><tr><td>AUTOSAR_SWS_TimeService.pdf</td><td>时间服务模块</td></tr><tr><td>AUTOSAR_SWS_DefaultErrorTracer.pdf</td><td>DET 模块</td></tr><tr><td>AUTOSAR_SWS_FunctionInhibitionManager.pdf</td><td>FIM 模块</td></tr></tbody></table><h3 id="mcal" tabindex="-1">MCAL <a class="header-anchor" href="#mcal" aria-label="Permalink to “MCAL”">​</a></h3><table tabindex="0"><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>AUTOSAR_SWS_MCUDriver.pdf</td><td>微控制器初始化</td></tr><tr><td>AUTOSAR_SWS_GPTDriver.pdf</td><td>通用定时器驱动</td></tr><tr><td>AUTOSAR_SWS_CoreTest.pdf</td><td>微控制器核心测试</td></tr><tr><td>AUTOSAR_SRS_SPALGeneral.pdf</td><td>微控制器 / ECU 抽象层通用需求</td></tr></tbody></table><p>更多的文件分类可以参考：<a href="AUTOSAR%20%E6%A0%87%E5%87%86%E6%96%87%E6%A1%A3/AUTOSAR_CP_TR_ReleaseOverview.pdf">AUTOSAR_CP_TR_ReleaseOverview</a></p><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to “目录”">​</a></h2><p>针对上图的架构，笔记目录为：</p><ul><li>Release Documentation</li><li>Application Interfaces</li><li>BSW General</li><li>Communication</li><li>Crypto</li><li>Diagnostics</li><li>General</li><li>GlobalTime</li><li>IO</li><li>Libraries</li><li>MCAL</li><li>Memory</li><li>Methodology and Templates <ul><li><a href="./Methodology and Templates/BSW Module Description Template.html">BSW Module Description Template</a></li><li><a href="./Methodology and Templates/Software Component Template.html">Software Component Template</a></li></ul></li><li>Mode Management</li><li>RTE</li><li>SWArch</li><li>Safety</li><li>Security</li><li>System Services</li></ul><h2 id="其他参考" tabindex="-1">其他参考 <a class="header-anchor" href="#其他参考" aria-label="Permalink to “其他参考”">​</a></h2><p><a href="https://blog.csdn.net/grey_csdn/category_10976751.html" target="_blank" rel="noreferrer">https://blog.csdn.net/grey_csdn/category_10976751.html</a><a href="https://blog.csdn.net/qq_350984705/article/details/138419822" target="_blank" rel="noreferrer">https://blog.csdn.net/qq_350984705/article/details/138419822</a></p><h2 id="文件结构" tabindex="-1">文件结构 <a class="header-anchor" href="#文件结构" aria-label="Permalink to “文件结构”">​</a></h2><p>AUTOSAR 官方文档分为多种：RS (Requirements Specification) 、 SWS (Software Specification)、SRS(Software Requirements Specification)、TR(Technical Report)、TPS(Template Specification)、EXP(Explanation Document)。</p><ul><li>RS：描述系统级别的需求</li><li>SRS：描述软件级别的详细需求</li><li>SWS：提供 AUTOSAR 标准的详细实现细节</li><li>TR：提供研究报告或经验总结，非强制性内容</li><li>TPS：定义文档或配置模板</li><li>EXP：提供对规范的详细解释和示例</li></ul><p>以下使用 Mcu 模块为例，介绍其标准的文件结构。</p><h3 id="requirements-specification" tabindex="-1">Requirements Specification <a class="header-anchor" href="#requirements-specification" aria-label="Permalink to “Requirements Specification”">​</a></h3><p><a href="AUTOSAR%20%E6%A0%87%E5%87%86%E6%96%87%E6%A1%A3/AUTOSAR_CP_RS_MCUDriver.pdf">AUTOSAR_CP_RS_MCUDriver</a></p><p>对于每个模块，本部分包括了对于标准用语的约定、缩略语的解释。这些内容是所有模块通用的。</p><p><img src="'+l+'" alt=""></p><p>文档还描述了该模块的功能概述（Functional Overview），包括模块驱动的功能概述。</p><p>此外，还描述了功能要求（Funcitonal Requirements）。</p><p>这些功能要求包含了对于配置项（Configuration）和初始化项（Initialization）的要求、对于正常运行状态（Normal Operation）的要求、对于故障（Fault）和停运（Shutdown）的要求等。不同的模块可能有所不同。</p><p><img src="'+o+'" alt=""></p><p>对于每一种要求，其均在 SRS 文档中进行了实现说明。</p><p>AUTOSAR 的实现厂商（如 Vector、ETAS），就会在这些系统要求的基础上编写软件，给出对应设置项的配置接口，并在这些设置的基础上生成符合 AUTOSAR 标准的代码。而对于这些代码的具体编写标准和实现细节，在 SWS 文档中有所描述。</p><h3 id="software-specification" tabindex="-1">Software Specification <a class="header-anchor" href="#software-specification" aria-label="Permalink to “Software Specification”">​</a></h3><p><a href="AUTOSAR%20%E6%A0%87%E5%87%86%E6%96%87%E6%A1%A3/AUTOSAR_CP_SWS_MCUDriver.pdf">AUTOSAR_CP_SWS_MCUDriver</a></p><p>文档首先对模块本身的功能和工作原理进行概述，同时列举了其驱动编写需要实现的功能。</p><p><img src="'+n+'" alt=""></p><p>文档还提供了相关的标准规范，可以以此为节点发散了解。</p><p><img src="'+S+'" alt=""></p><p>文档还会包含该模块对于其他模块的依赖关系和相互作用。如 Mcu 模块，文档提供了其对于启动代码（Start-up Code）的依赖关系，并阐明 Mcu 与其的交互关系。比如当 Mcu 开启了某种设置后，在 Start-up Code 中应当做什么样的实现。</p><blockquote><p>SWS 中不应当提供对于文件结构的定义</p></blockquote><p>接下来，文档对于模块的实现进行了规范。形如：</p><p><img src="'+p+'" alt=""></p><p>这些规范覆盖了该模块应当具有的所有功能，包括错误处理、错误应当返回的状态码等。</p><p><img src="'+A+'" alt=""></p><p>文档标注了 API 的规范，即对于模块的具体实现，应当有什么样的函数名、变量名等。</p><p><img src="'+s+'" alt="类型定义"> （类型定义）</p><p>文档描述了序列图（Sequence Diagram）。该部分演示了模块运行的过程。</p><p><img src="'+h+'" alt=""></p><p>文档提供了对于配置的标准限值（Configuration specification）。该部分内容提示了实现厂商应当提供什么样的接口，应当有如何的选项。</p><p><img src="'+c+'" alt=""></p><blockquote><p>值得一提的是，该部分的解释与 EB tresos Studio 官方 User Manual 手册中关于配置的介绍是基本相同的，因为 EB tresos Studio 是符合 AUTOSAR 标准的配置软件。具体详见：<a href="./../AUTOSAR PRAC/EB Tresos Mcal 最小系统搭建.html">EB Tresos Mcal 最小系统搭建</a></p></blockquote><h3 id="template-specification" tabindex="-1">Template Specification <a class="header-anchor" href="#template-specification" aria-label="Permalink to “Template Specification”">​</a></h3><p><a href="AUTOSAR%20%E6%A0%87%E5%87%86%E6%96%87%E6%A1%A3/AUTOSAR_CP_TPS_BSWModuleDescriptionTemplate.pdf">AUTOSAR_CP_TPS_BSWModuleDescriptionTemplate</a></p><p>(这部分在 <a href="./Methodology and Templates/BSW Module Description Template.html">BSW Module Description Template</a> 中有所介绍)</p><p><a href="AUTOSAR%20%E6%A0%87%E5%87%86%E6%96%87%E6%A1%A3/AUTOSAR_CP_TPS_SoftwareComponentTemplate.pdf">AUTOSAR_CP_TPS_SoftwareComponentTemplate</a></p><p>(这部分在 <a href="./Methodology and Templates/Software Component Template.html">Software Component Template</a> 中有所介绍)</p><p>这部分文件描述了一些元规范（Meta-Spec），用于规定文档结构、元素关系、参数属性等，比如 BSW 的模块描述、EcuC 配置模型、Arxml Schema 描述规范等。其决定了 AUTOSAR 配置工具配置语法的定义。</p>',79)])])}const P=e(_,[["render",T]]);export{u as __pageData,P as default};
